// Conceptually (simplified):
int simpleHash(string key, int bucketCount)
{
    int sum = 0;
    for (char c : key)
    {
        sum += c; // add up character codes
    }
    return sum % bucketCount; // squeeze into a fixed number of "buckets"
}

#include <iostream>
#include <vector>
#include <unordered_map>

using namespace std;

int main()
{
    vector<int> numbers = {2, 7, 11, 15};
    int target = 9;

    unordered_map<int, int> seen; // value -> index

    for (int i = 0; i < numbers.size(); i++)
    {
        int complement = target - numbers[i];

        if (seen.count(complement))
        {
            cout << seen[complement] << " " << i << endl;
            break;
        }

        seen[numbers[i]] = i;
    }

    return 0;
}

